import{_ as a,o as t,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"71. Examination Leave","description":"","frontmatter":{"title":"71. Examination Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","study-leave","wages","classifications"]},"headers":[],"relativePath":"ebas/mspp/leave/71-examination-leave.md","filePath":"ebas/mspp/leave/71-examination-leave.md"}'),o={name:"ebas/mspp/leave/71-examination-leave.md"};function s(r,e,l,p,m,d){return t(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_71-examination-leave" tabindex="-1">71. Examination Leave <a class="header-anchor" href="#_71-examination-leave" aria-label="Permalink to &quot;71. Examination Leave&quot;">​</a></h1><p><strong>a.</strong> An Employee shall be granted leave with full wages in order to attend examinations necessary to obtain a higher qualification as specified by this Agreement provided that such examinations are held within Australia.</p><p><strong>b.</strong> The amount of such leave shall be sufficient to allow the Employee:</p><p><strong>(i)</strong> to proceed to and from the place of examination; and</p><p><strong>(ii)</strong> in addition, to allow three clear days prior to the oral examination and either three clear days or three single days prior to the written papers with a maximum of six days pre-examination study leave in any calendar year.</p><p><strong>c.</strong> A Pharmacist Intern shall be granted one clear day pre-examination study leave with full wages and paid sufficient time to allow the Employee to proceed to and from the place of examination to attend the Pharmacy (VI) final examinations.</p><p><strong>d.</strong> Any leave granted under the provision of this clause shall be in addition to the provisions of <a href="/eba/ebas/mspp/leave/61-annual-leave.html">clause 61</a> - Annual Leave.</p><p>Plain language terms: exam leave.</p>',8)])])}const v=a(o,[["render",s]]);export{c as __pageData,v as default};
